) AS v(country, ean, ingredient_name, position, percent, percent_estimate, is_sub_ingredient, parent_ingredient_name)
JOIN products p ON p.country = v.country AND p.ean = v.ean
JOIN ingredient_ref ir ON lower(ir.name_en) = lower(v.ingredient_name)
LEFT JOIN ingredient_ref ir_parent ON lower(ir_parent.name_en) = lower(v.parent_ingredient_name)
WHERE p.is_deprecated IS NOT TRUE
  AND NOT (v.is_sub_ingredient AND ir_parent.ingredient_id IS NULL)
ON CONFLICT (product_id, ingredient_id, position) DO NOTHING;

